const express = require('express');
const jwt = require('jsonwebtoken');

// In production, use environment variables and a strong secret
const JWT_SECRET = process.env.JWT_SECRET;

if (!JWT_SECRET) {
  throw new Error('JWT_SECRET environment variable must be set. Do not use a hardcoded secret.');
}

const ALLOWED_ALGORITHMS = ['HS256'];

function jwtVerifyMiddleware(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader) {
    return res.status(401).json({ error: 'Authorization header is missing' });
  }

  const parts = authHeader.split(' ');

  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    return res.status(401).json({ error: 'Authorization header must be in the format: Bearer <token>' });
  }

  const token = parts[1];

  if (!token || token.trim() === '') {
    return res.status(401).json({ error: 'Token is empty' });
  }

  try {
    // Verify the token with explicit algorithm restriction to prevent algorithm confusion attacks
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ALLOWED_ALGORITHMS, // Prevent "none" algorithm and algorithm switching attacks
      complete: false,
    });

    // Validate that the decoded payload has expected user fields
    if (!decoded || typeof decoded !== 'object') {
      return res.status(401).json({ error: 'Invalid token payload' });
    }

    if (!decoded.sub && !decoded.userId) {
      return res.status(401).json({ error: 'Token missing user identifier (sub or userId)' });
    }

    // Check token expiration explicitly (jwt.verify does this, but belt-and-suspenders)
    if (decoded.exp && Date.now() >= decoded.exp * 1000) {
      return res.status(401).json({ error: 'Token has expired' });
    }

    // Attach user info to request object
    req.user = {
      id: decoded.sub || decoded.userId,
      email: decoded.email || null,
      role: decoded.role || null,
      iat: decoded.iat,
      exp: decoded.exp,
    };

    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token has expired' });
    }
    if (err.name === 'JsonWebTokenError') {
      return res.status(401).json({ error: 'Invalid token' });
    }
    if (err.name === 'NotBeforeError') {
      return res.status(401).json({ error: 'Token is not yet active' });
    }
    return res.status(401).json({ error: 'Token verification failed' });
  }
}

// Optional: Role-based authorization middleware to use after jwtVerifyMiddleware
function requireRole(...allowedRoles) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    if (!req.user.role || !allowedRoles.includes(req.user.role)) {
      return res.status(403).json({ error: 'Insufficient permissions' });
    }

    next();
  };
}

// Helper to generate tokens (for login endpoints, etc.)
function generateToken(user, expiresIn = '1h') {
  if (!user || !user.id) {
    throw new Error('User object with id is required to generate a token');
  }

  const payload = {
    sub: user.id,
    email: user.email || null,
    role: user.role || null,
  };

  return jwt.sign(payload, JWT_SECRET, {
    algorithm: ALLOWED_ALGORITHMS[0],
    expiresIn: expiresIn,
  });
}

// --- Example Express app demonstrating usage ---

const app = express();
app.use(express.json());

// Public route - no auth needed
app.post('/api/login', (req, res) => {
  const { email, password } = req.body;

  // In production, validate credentials against a database with hashed passwords
  // This is a prototype stub
  if (email === 'user@example.com' && password === 'password123') {
    const token = generateToken({ id: '12345', email: email, role: 'user' });
    return res.json({ token });
  }

  if (email === 'admin@example.com' && password === 'admin123') {
    const token = generateToken({ id: '00001', email: email, role: 'admin' });
    return res.json({ token });
  }

  return res.status(401).json({ error: 'Invalid credentials' });
});

// Protected route - requires valid JWT
app.get('/api/profile', jwtVerifyMiddleware, (req, res) => {
  res.json({
    message: 'Authenticated successfully',
    user: req.user,
  });
});

// Protected route with role check
app.get('/api/admin/dashboard', jwtVerifyMiddleware, requireRole('admin'), (req, res) => {
  res.json({
    message: 'Welcome to the admin dashboard',
    user: req.user,
  });
});

// Apply middleware to all routes under a path
app.use('/api/protected', jwtVerifyMiddleware);

app.get('/api/protected/data', (req, res) => {
  res.json({
    message: 'This is protected data',
    user: req.user,
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = {
  jwtVerifyMiddleware,
  requireRole,
  generateToken,
  app,
};